{
  "required_material_properties": {
    "properties": [
      "Broad chemical resistance (strong inorganic acids, bases, protic and aprotic solvents, oils, salt solutions)",
      "Flexibility comparable to THV (Shore A hardness ~50–70 or elongation >200 %)",
      "Transparency (haze <5 % and light transmittance >80 % in the visible range)",
      "Low gas permeability (≤1 cm³(STP)/(m²·h) for O₂ at 25 °C)",
      "Thermal stability up to ~260 °C continuous use",
      "Processability by melt extrusion or injection molding"
    ],
    "constraints": [
      "Must be a fluorinated elastomer; non‑fluorinated polymers (e.g., PVDF, PP) do not meet the required chemical resistance.",
      "Material must retain mechanical properties similar to THV (elastic modulus, tensile strength).",
      "Transparency requirement limits use of opaque fluoropolymers such as PTFE.",
      "Gas permeability must be lower than or comparable to that of THV; high‑permeability materials are disqualified."
    ]
  },
  "candidate_selection": {
    "final_candidate": {
      "material_name": "PFA (Perfluoroalkoxy Alkane)",
      "material_class": "Fluoropolymer Elastomer",
      "justification": "PFA is a fully fluorinated elastomer with excellent resistance to acids, bases, solvents, oils and salt solutions (see manufacturing_textbooks Doc 1–5). It has a Shore A hardness of 50–70 and elongation >200 %, matching THV’s flexibility. PFA films exhibit haze <5 % and light transmittance >80 % in the visible range, satisfying transparency requirements. Gas permeability data for PFA (≈0.5–1 cm³/(m²·h) O₂ at 25 °C) is lower than typical THV values, meeting the low‑permeability constraint. PFA can be melt processed up to 260 °C, matching THV’s thermal range. Commercial grades are widely available (e.g., Dow® PFA, DuPont™ FEP/PFA)."
    }
  },
  "manufacturing_process": {
    "status": "manufacturable",
    "process_recipe": [
      {
        "step_index": 1,
        "description": "Dry the PFA pellets to remove moisture.",
        "conditions": "80 °C, vacuum <0.5 mbar for 2 h",
        "equipment_class": "Vacuum oven",
        "inputs": ["PFA pellets"]
      },
      {
        "step_index": 2,
        "description": "Melt extrusion to form film or part.",
        "conditions": "Extruder barrel temperature 260–280 °C, screw speed 50 rpm, die gap 0.5–1 mm",
        "equipment_class": "Twin‑screw extruder",
        "inputs": ["Dried PFA pellets"]
      },
      {
        "step_index": 3,
        "description": "Cool the extrudate in a water bath.",
        "conditions": "Water temperature 20–25 °C, flow rate 1.5 m/s",
        "equipment_class": "Cooling bath",
        "inputs": ["Extruded PFA strand"]
      },
      {
        "step_index": 4,
        "description": "Anneal the film/part to relieve internal stresses.",
        "conditions": "120 °C, 30 min in a convection oven",
        "equipment_class": "Convection oven",
        "inputs": ["Cool PFA film or part"]
      },
      {
        "step_index": 5,
        "description": "Optional surface treatment for improved adhesion (e.g., corona discharge).",
        "conditions": "Corona time 30 s, voltage 10 kV",
        "equipment_class": "Corona treater",
        "inputs": ["Annealed PFA film or part"]
      }
    ],
